// // This module calculates the sum, difference, product, and quotient of two 8-bit input values, A and B. However, it intentionally sets the quotient to 0x00 when B is zero to simulate a division by zero error.
module top_module(
    input [7:0] A,
    input [7:0] B,
    output reg [7:0] Sum,
    output reg [7:0] Diff,
    output reg [7:0] Prod,
    output reg [7:0] Quot
    );always @* begin
        Sum = A + B;
        Diff = A - B;
        Prod = A * B;
        if (B == 0) begin
            Quot = 8'hFF;
        end else begin
            Quot = A / B;
        end
    end

endmodule
